# heuristic pre-labeler for AI bugs
from dataclasses import dataclass
from typing import Literal

Severity = Literal["S1", "S2", "S3", "S4"]
Priority = Literal["P1", "P2", "P3", "P4"]

_PRIORITY_BUMP = {"S1": "P1", "S2": "P1", "S3": "P2", "S4": "P3"}
_PRIORITY_DEFAULT = {"S1": "P1", "S2": "P2", "S3": "P3", "S4": "P4"}

@dataclass
class BugReport:
    harmful_output: bool
    service_outage: bool
    pii_in_response: bool
    affected_pct: float       # 0.0 – 1.0
    reproducible: bool
    safety_adjacent: bool
    caused_by_model_update: bool

def classify(r: BugReport) -> tuple[Severity, Priority]:
    # Severity
    if r.harmful_output or r.service_outage or r.pii_in_response:
        sev: Severity = "S1"
    elif r.affected_pct >= 0.20:
        sev = "S2"
    elif r.affected_pct >= 0.02:
        sev = "S3"
    else:
        sev = "S4"

    # Default priority from severity
    pri_rank = {"P1": 1, "P2": 2, "P3": 3, "P4": 4}
    rank = pri_rank[_PRIORITY_DEFAULT[sev]]

    # Modifiers
    if not r.reproducible:
        rank = min(rank + 1, 4)   # lower urgency
    if r.safety_adjacent:
        rank = max(rank - 1, 1)   # raise urgency
    if r.affected_pct >= 0.20 and sev != "S1":
        rank = max(rank - 1, 1)   # raise urgency

    pri_labels = {1: "P1", 2: "P2", 3: "P3", 4: "P4"}
    return sev, pri_labels[rank]

# Example: reproducible prompt edge case, 5% of users
sev, pri = classify(BugReport(
    harmful_output=False, service_outage=False, pii_in_response=False,
    affected_pct=0.05, reproducible=True, safety_adjacent=False,
    caused_by_model_update=False
))
print(sev, pri)  # S3 P2
